/**
 * One-shot backfill: insert one flagger row per `(project, strategy slug)`
 * for every existing project, using real CUID2 ids generated by `createId()`.
 *
 * Why this is a Node script and not a Drizzle SQL migration:
 *   The flagger row id is a CUID2 (length 24, base36, mint-collision-free).
 *   Postgres has no native CUID2 generator, and approximations
 *   (`gen_random_uuid()` slices, hex hashes) violate the format.
 *   Drizzle migrations are SQL-only, so the backfill ships as a TS script
 *   instead of bundled inside `pg:migrate`.
 *
 * Idempotency: the unique `(organization_id, project_id, slug)` index makes
 * `INSERT ... ON CONFLICT DO NOTHING` safe to re-run any number of times.
 *
 * Run **once** in each environment after `pg:migrate` has applied
 * `add-flaggers-table`. New projects do not need this — the workers app
 * provisions flaggers on `ProjectCreated`.
 *
 *     pnpm --filter @platform/db-postgres pg:backfill:flaggers
 */
import { existsSync } from "node:fs"
import { fileURLToPath } from "node:url"
import { listQueueStrategySlugs } from "@domain/annotation-queues"
import { parseEnv } from "@platform/env"
import { createId } from "@paralleldrive/cuid2"
import { config as loadDotenv } from "dotenv"
import { Effect } from "effect"
import { closePostgres, createPostgresClient } from "../src/client.ts"
import { projects } from "../src/schema/projects.ts"
import { flaggers } from "../src/schema/flaggers.ts"
import { FLAGGER_DEFAULT_SAMPLING } from "@domain/annotation-queues"

const nodeEnv = Effect.runSync(parseEnv("NODE_ENV", "string", "development"))
const envFilePath = fileURLToPath(new URL(`../../../../.env.${nodeEnv}`, import.meta.url))

if (existsSync(envFilePath)) {
  loadDotenv({ path: envFilePath, quiet: true })
}

const main = async () => {
  const adminUrl = Effect.runSync(parseEnv("LAT_ADMIN_DATABASE_URL", "string"))
  const client = createPostgresClient({ databaseUrl: adminUrl })

  const slugs = listQueueStrategySlugs()
  console.log(`Backfilling flaggers for ${slugs.length} strategies: ${slugs.join(", ")}`)

  try {
    const allProjects = await client.db.select({ id: projects.id, organizationId: projects.organizationId }).from(projects)
    console.log(`Found ${allProjects.length} project(s)`)

    if (allProjects.length === 0) {
      console.log("No projects to backfill. Done.")
      return
    }

    const now = new Date()
    const rows = allProjects.flatMap((project) =>
      slugs.map((slug) => ({
        id: createId(),
        organizationId: project.organizationId,
        projectId: project.id,
        slug,
        enabled: true,
        sampling: FLAGGER_DEFAULT_SAMPLING,
        createdAt: now,
        updatedAt: now,
      })),
    )

    // Insert in chunks to keep parameter counts under Postgres' 65535 limit.
    // Each row uses 8 columns, so ~8000 rows per batch is a safe ceiling.
    const BATCH_SIZE = 5000
    let inserted = 0
    for (let i = 0; i < rows.length; i += BATCH_SIZE) {
      const batch = rows.slice(i, i + BATCH_SIZE)
      const result = await client.db
        .insert(flaggers)
        .values(batch)
        .onConflictDoNothing({
          target: [flaggers.organizationId, flaggers.projectId, flaggers.slug],
        })
        .returning({ id: flaggers.id })
      inserted += result.length
    }

    console.log(`Inserted ${inserted} new flagger row(s) (skipped ${rows.length - inserted} existing).`)
  } finally {
    await closePostgres(client)
  }
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})
